# TypeScript Type System

TypeScript's type system catches bugs at compile time by tracking the shape of every value through your program. It is structural (shape-based, not name-based) and gradual (you can opt in or out of strictness).

## Primitive Types

```typescript
let str: string = "hello";
let num: number = 42;
let big: bigint = 9007199254740991n;
let bool: boolean = true;
let sym: symbol = Symbol("id");
let undef: undefined = undefined;
let nul: null = null;
let v: void = undefined;        // functions that return nothing
let n: never;                    // functions that never return (throws, infinite loop)
let a: any;                      // opt out of type checking
let u: unknown;                  // type-safe alternative to any
```

### `any` vs `unknown`

`any` disables type checking — anything goes. `unknown` is type-safe: you must narrow before using.

```typescript
function processAny(val: any) {
  val.foo();          // No error — dangerous
  val.toUpperCase();  // No error — could crash at runtime
}

function processUnknown(val: unknown) {
  // val.foo();       // Error: Object is of type 'unknown'
  if (typeof val === "string") {
    val.toUpperCase(); // OK — narrowed to string
  }
}
```

## Literal Types

Exact values as types. Combine with unions for enumerations.

```typescript
let direction: "north" | "south" | "east" | "west";
direction = "north"; // OK
// direction = "up"; // Error: not assignable

let httpStatus: 200 | 201 | 400 | 404 | 500;
let isActive: true | false; // equivalent to boolean
```

## Union Types

A value that could be one of several types.

```typescript
type StringOrNumber = string | number;

function format(val: string | number): string {
  if (typeof val === "string") {
    return val.toUpperCase();  // narrowed to string
  }
  return val.toFixed(2);       // narrowed to number
}

// Nullable types
type MaybeString = string | null | undefined;
```

## Intersection Types

Combine multiple types into one. The result has all properties from all types.

```typescript
type HasName = { name: string };
type HasAge = { age: number };
type Person = HasName & HasAge;

const person: Person = { name: "Alice", age: 30 }; // must have both
```

## Type Narrowing

TypeScript tracks type information through control flow. After a check, the type is narrowed.

### typeof narrowing

```typescript
function process(val: string | number | boolean) {
  if (typeof val === "string") {
    // val is string here
    return val.trim();
  } else if (typeof val === "number") {
    // val is number here
    return val.toFixed(2);
  } else {
    // val is boolean here
    return val.toString();
  }
}
```

### instanceof narrowing

```typescript
function getDate(val: string | Date): string {
  if (val instanceof Date) {
    return val.toISOString(); // narrowed to Date
  }
  return val; // narrowed to string
}
```

### in narrowing

```typescript
type Fish = { swim: () => void };
type Bird = { fly: () => void };

function move(animal: Fish | Bird) {
  if ("swim" in animal) {
    animal.swim(); // narrowed to Fish
  } else {
    animal.fly();  // narrowed to Bird
  }
}
```

### Truthiness narrowing

```typescript
function greet(name: string | null) {
  if (name) {
    console.log(`Hello, ${name}!`); // narrowed to string
  }
}
```

## Type Guards

Custom functions that narrow types with the `is` keyword.

```typescript
interface Cat { meow(): void; }
interface Dog { bark(): void; }

function isCat(pet: Cat | Dog): pet is Cat {
  return (pet as Cat).meow !== undefined;
}

function interact(pet: Cat | Dog) {
  if (isCat(pet)) {
    pet.meow();  // narrowed to Cat
  } else {
    pet.bark();  // narrowed to Dog
  }
}
```

TypeScript 5.5+ can infer type predicates automatically in some cases.

## Discriminated Unions

The most important pattern for modeling states. Use a literal property as a tag.

```typescript
type Result<T> =
  | { status: "success"; data: T }
  | { status: "error"; error: Error }
  | { status: "loading" };

function handleResult(result: Result<string>) {
  switch (result.status) {
    case "success":
      console.log(result.data);   // data is accessible
      break;
    case "error":
      console.error(result.error); // error is accessible
      break;
    case "loading":
      console.log("Loading...");
      break;
  }
}

// Exhaustiveness checking
function assertNever(x: never): never {
  throw new Error(`Unexpected: ${x}`);
}

function handle(result: Result<string>) {
  switch (result.status) {
    case "success": return result.data;
    case "error": return result.error.message;
    case "loading": return "...";
    default: return assertNever(result); // compile error if a case is missing
  }
}
```

## Interfaces vs Type Aliases

```typescript
// Interface — extendable, declaration-merged, for object shapes
interface User {
  id: string;
  name: string;
}

interface Admin extends User {
  role: "admin";
}

// Type alias — for unions, intersections, primitives, tuples
type ID = string | number;
type Pair = [string, number];
type Callback = (err: Error | null, data: string) => void;

// Both work for objects — prefer interface for public APIs (better error messages)
type UserType = {
  id: string;
  name: string;
};
```

Key difference: interfaces can be declaration-merged (multiple `interface User` blocks merge). Type aliases cannot.

## Tuple Types

```typescript
// Fixed-length array with known element types
type Point = [number, number];
type NamedPoint = [x: number, y: number, label: string]; // labeled

const origin: Point = [0, 0];

// Rest elements in tuples
type StringNumberBooleans = [string, number, ...boolean[]];
type LeadingRest = [...string[], number]; // strings followed by a number

// Readonly tuples
type ReadonlyPoint = readonly [number, number];
const p: ReadonlyPoint = [1, 2];
// p[0] = 3; // Error: readonly

// as const for tuple inference
const colors = ["red", "green", "blue"] as const;
// type: readonly ["red", "green", "blue"]
```

## Template Literal Types

```typescript
type EventName = `on${"Click" | "Hover" | "Focus"}`;
// "onClick" | "onHover" | "onFocus"

type HTTPMethod = "GET" | "POST" | "PUT" | "DELETE";
type Endpoint = `/api/${string}`;
type Route = `${HTTPMethod} ${Endpoint}`;
// "GET /api/${string}" | "POST /api/${string}" | ...

// Intrinsic string manipulation types
type Upper = Uppercase<"hello">;     // "HELLO"
type Lower = Lowercase<"HELLO">;     // "hello"
type Cap = Capitalize<"hello">;      // "Hello"
type Uncap = Uncapitalize<"Hello">; // "hello"
```

## Conditional Types

Types that branch based on a condition.

```typescript
type IsString<T> = T extends string ? true : false;

type A = IsString<"hello">;  // true
type B = IsString<42>;       // false

// Distributive conditional types — distributes over unions
type ToArray<T> = T extends unknown ? T[] : never;
type C = ToArray<string | number>;  // string[] | number[]

// Non-distributive (wrap in tuple)
type ToArrayNonDist<T> = [T] extends [unknown] ? T[] : never;
type D = ToArrayNonDist<string | number>;  // (string | number)[]

// infer — extract types from other types
type ReturnOf<T> = T extends (...args: any[]) => infer R ? R : never;
type E = ReturnOf<() => string>;  // string

type ElementType<T> = T extends (infer E)[] ? E : never;
type F = ElementType<number[]>;   // number

type Awaited2<T> = T extends Promise<infer U> ? Awaited2<U> : T;
type G = Awaited2<Promise<Promise<string>>>;  // string
```

## Mapped Types

Transform properties of an existing type.

```typescript
// Make all properties optional
type MyPartial<T> = { [K in keyof T]?: T[K] };

// Make all properties readonly
type MyReadonly<T> = { readonly [K in keyof T]: T[K] };

// Rename keys with 'as' clause
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};

interface Person {
  name: string;
  age: number;
}

type PersonGetters = Getters<Person>;
// { getName: () => string; getAge: () => number }

// Filter keys
type OnlyStrings<T> = {
  [K in keyof T as T[K] extends string ? K : never]: T[K];
};
```

## Indexed Access Types

Look up a type by indexing into another type.

```typescript
interface User {
  id: number;
  name: string;
  address: {
    street: string;
    city: string;
  };
}

type UserId = User["id"];           // number
type UserAddress = User["address"]; // { street: string; city: string }
type Street = User["address"]["street"]; // string

// Index with a union
type IdOrName = User["id" | "name"]; // number | string

// Index with keyof
type UserValues = User[keyof User]; // number | string | { street; city }

// Array element type
type Arr = string[];
type Elem = Arr[number]; // string

// Const array element type
const roles = ["admin", "user", "guest"] as const;
type Role = (typeof roles)[number]; // "admin" | "user" | "guest"
```

## Built-in Utility Types

```typescript
// Object manipulation
Partial<T>           // Make all properties optional
Required<T>          // Make all properties required
Readonly<T>          // Make all properties readonly
Pick<T, K>           // Select specific properties
Omit<T, K>           // Remove specific properties
Record<K, V>         // Object type with keys K and values V

// Union manipulation
Exclude<T, U>        // Remove types from a union
Extract<T, U>        // Keep only types assignable to U
NonNullable<T>       // Remove null and undefined

// Function types
ReturnType<T>        // Get return type of a function type
Parameters<T>        // Get parameter types as a tuple
ConstructorParameters<T>  // Get constructor parameter types
InstanceType<T>      // Get instance type of a constructor
ThisParameterType<T> // Get 'this' parameter type
OmitThisParameter<T> // Remove 'this' parameter

// Promise
Awaited<T>           // Unwrap Promise (recursively)

// String
Uppercase<T>         // Convert string literal to uppercase
Lowercase<T>         // Convert string literal to lowercase
Capitalize<T>        // Capitalize first letter
Uncapitalize<T>      // Uncapitalize first letter

// Other
NoInfer<T>           // Prevent type inference in this position (5.4+)
Satisfies<T, U>      // Validate T satisfies U (no widening)
```

### Utility Type Examples

```typescript
interface User {
  id: number;
  name: string;
  email: string;
  role: "admin" | "user";
}

type UserUpdate = Partial<User>;                    // all optional
type UserRequired = Required<User>;                 // all required
type UserReadonly = Readonly<User>;                  // all readonly
type UserPreview = Pick<User, "id" | "name">;       // only id and name
type UserWithoutEmail = Omit<User, "email">;         // everything except email
type UserMap = Record<string, User>;                 // { [key: string]: User }

type NonAdminRole = Exclude<User["role"], "admin">; // "user"
type AdminRole = Extract<User["role"], "admin">;    // "admin"

type MaybeString = string | null | undefined;
type JustString = NonNullable<MaybeString>;          // string

function createUser(name: string, email: string): User {
  return { id: 1, name, email, role: "user" };
}
type CreateUserReturn = ReturnType<typeof createUser>;  // User
type CreateUserParams = Parameters<typeof createUser>;  // [string, string]
```

## The `satisfies` Operator (4.9+)

Validates a value matches a type without widening it.

```typescript
type ColorMap = Record<string, string | number[]>;

// With 'as' — loses literal types
const colors1 = {
  red: "#ff0000",
  green: [0, 255, 0],
} as ColorMap;
// colors1.red is string | number[] — widened

// With 'satisfies' — keeps literal types
const colors2 = {
  red: "#ff0000",
  green: [0, 255, 0],
} satisfies ColorMap;
// colors2.red is string — precise
// colors2.green is number[] — precise
```

## `as const` Assertions

Make values deeply readonly with literal types.

```typescript
const config = {
  apiUrl: "https://api.example.com",
  timeout: 5000,
  retries: 3,
} as const;
// type: { readonly apiUrl: "https://api.example.com"; readonly timeout: 5000; readonly retries: 3 }

const DIRECTIONS = ["north", "south", "east", "west"] as const;
type Direction = (typeof DIRECTIONS)[number]; // "north" | "south" | "east" | "west"
```
